<template>
  <div class="user-details">
    <div class="user-account">
      <div class="account-header">
        <h4 class="pb-2">My account</h4>
      </div>

      <a-form-model class="pt-3 pb-4" ref="ruleForm" :model="form" :rules="rules" layout="vertical"
                    @submit.prevent="onSubmit()"
                    @keydown="form.onKeydown($event)" :hideRequiredMark="true">
        <div class="form-header">
          <div class="header-des">
            <p>Personal information</p>
            <button v-if="profile" @click.prevent="profile = false"><span>Cancel</span></button>
            <button v-else @click.prevent="profile = true"><span>Edit</span></button>
          </div>
        </div>
        <div class="row">
          <div class="col-md-4 col-12">
            <a-form-model-item class="mb-0" label="Full name :" ref="name" prop="name">
              <a-input v-if="profile" v-model="form.name" placeholder="Enter your first and last name"/>
              <p v-else>{{ form.name }}</p>
            </a-form-model-item>
          </div>
          <div class="col-md-4 col-12">
            <a-form-model-item label="Gender :">
              <a-select v-if="profile" v-model="form.gender" placeholder="please select gender">
                <a-select-option value="male">
                  male
                </a-select-option>
                <a-select-option value="women">
                  women
                </a-select-option>
              </a-select>
              <p v-else>{{ form.gender }}</p>
            </a-form-model-item>
          </div>
          <div class="col-12 col-md-4">
            <a-form-model-item label="Birthday :">
              <a-date-picker v-if="profile" :default-value="form.birthday" format="YYYY-MM-DD"
                             @change="dateSelect"
                             placeholder="Pick a date"/>
              <p v-else>{{ form.birthday }}</p>
            </a-form-model-item>
          </div>
        </div>
        <div class="row" v-if="profile">
          <div class="col-12">
            <a-button htmlType="submit" class="px-5 text-white" size="large" :loading="form.busy"
                      style="background-color: #6aa1cf"
                      :disabled="form.busy">Update Profile
            </a-button>
          </div>
        </div>
      </a-form-model>

      <form class="pt-3 pb-4">
        <div class="row">
          <div class="col-md-6 col-12">
            <p style="color: black">Email Address |
              <a href="#" style="font-size: 12px" @click.prevent="emailModel = true">
                {{ user.email ? "Change" : "Add" }}
              </a>
            </p>
            <span class="ant-form-text">{{ user.email }}</span>
          </div>
          <div class="col-md-6 col-12">
            <p style="color: black">Phone Number|
              <a href="#" style="font-size: 12px">
                {{ user.mobile ? "Change" : "Add" }}
              </a>
            </p>
            <span class="ant-form-text">{{ user.mobile }}</span>
          </div>
        </div>
      </form>
    </div>
    <Email :modelOpen="emailModel" :is-update="!!user.email" @closeModel="emailModel = false" :name="form.name"/>
  </div>
</template>

<script>
import {mapGetters} from "vuex";
import moment from "moment";
import Email from "@/components/customer/Email";

export default {
  name: "Profile",
  components: {Email},
  data() {
    return {
      profile: false,
      emailModel: false,
      form: new Form({
        name: '',
        gender: undefined,
        birthday: null,
      }),
      rules: {
        name: [
          {required: true, message: 'Please enter your name', trigger: 'blur'},
          {max: 100, message: 'Name maximum length 100 character', trigger: 'blur'},
        ],
      }
    }
  },
  methods: {
    dateSelect(date) {
      this.form.birthday = moment(date).format('YYYY-MM-DD');
    },
    onSubmit() {
      this.$refs.ruleForm.validate(valid => {
        if (valid) {
          this.form.post('profile-update')
              .then(() => {
                this.$notification['success']({
                  message: 'congratulations',
                  description: 'Profile update successfully.',
                  style: {marginTop: '200px'},
                });
                this.$store.dispatch('VERIFY_AUTH');
                this.profile = false;
              })
              .catch(err => {
                this.$notification['error']({
                  message: 'Warning',
                  description: ((err.response || {}).data || {}).message || 'Something Wrong',
                  style: {marginTop: '200px'},
                  duration: 5
                })
              })
        } else {
          return false;
        }
      });
    }
  },
  created() {
    this.form.fill(this.user);
  },
  watch: {
    user: function () {
      this.form.fill(this.user);
    },
    profile: function () {
      this.form.fill(this.user);
    }
  },
  computed: {
    ...mapGetters({user: "currentUser"})
  }
}
</script>

